.verb-widget .milo-tooltip::before {
  content: attr(data-tooltip);
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  left: 100%;
  margin-left: 7px;
  max-width: 140px;
  padding: 10px;
  border-radius: 5px;
  background: #0469E3;
  color: #fff;
  text-align: left;
  display: none;
  z-index: 8;
  font-size: 12px;
  font-style: normal;
  font-weight: 400;
  line-height: 16px;
  width: max-content;
}

.verb-widget .milo-tooltip::after {
  content: "";
  position: absolute;
  left: 100%;
  margin-left: -8px;
  top: 50%;
  transform: translateY(-50%);
  border: 8px solid #0469E3;
  border-color: transparent #0469E3 transparent transparent;
  display: none;
  z-index: 8;
}

.verb-widget .milo-tooltip.top::before {
  left: 50%;
  transform: translateX(-50%) translateY(-100%);
  top: -6px;
  margin-bottom: 15px;
  margin-left: 0;
}

.verb-widget .milo-tooltip.top::after {
  left: 50%;
  top: 2px;
  transform: translateX(-50%) translateY(-50%);
  border: 8px solid #0469E3;
  border-color: #0469E3 transparent transparent;
  margin-left: 0;
}

.verb-widget .milo-tooltip:hover::before,
.verb-widget .milo-tooltip:focus::before,
.verb-widget .milo-tooltip:active::before {
  display: block; 
}

.verb-widget .milo-tooltip:hover::after,
.verb-widget .milo-tooltip:focus::after,
.verb-widget .milo-tooltip:active::after {
  display: block;
}

@supports (-webkit-backdrop-filter: blur(1px)) and (not (backdrop-filter: blur(1px))) {
  .verb-widget .milo-tooltip:focus::before {
    outline: 4px solid -webkit-focus-ring-color;
    outline-offset: 1px;
  }
}

@media screen and (max-width: 1199px) {
  .verb-widget .mobile.milo-tooltip.top::before {
    left: 0;
    right: auto;
    transform: translateX(0) translateY(-100%);
    max-width: 200px;
  }

  .verb-widget .mobile.milo-tooltip.top::after {
    left: 4px;
    right: auto;
    transform: translateX(0) translateY(-50%);
  }

  .verb-widget .tablet.milo-tooltip.top::before,
  .verb-widget .milo-tooltip.top::before {
    left: auto;
    right: 0;
    transform: translateX(0) translateY(-100%);
    max-width: 200px;
  }

  .verb-widget .tablet.milo-tooltip.top::after,
  .verb-widget .milo-tooltip.top::after {
    left: auto;
    right: 4px;
    transform: translateX(0) translateY(-50%);
  }

  [dir="rtl"] .verb-widget .mobile.milo-tooltip.top::before,
  [dir="rtl"] .verb-widget .tablet.milo-tooltip.top::before {
    transform: translateX(0) translateY(-100%);
    text-align: right;
  }

  [dir="rtl"] .verb-widget .mobile.milo-tooltip.top::before {
    left: auto;
    right: 0;
  }

  [dir="rtl"] .verb-widget .mobile.milo-tooltip.top::after,
  [dir="rtl"] .verb-widget .tablet.milo-tooltip.top::after {
    transform: translateX(0) translateY(-50%);
  }

  [dir="rtl"] .verb-widget .mobile.milo-tooltip.top::after {
    left: auto;
    right: 4px;
  }

  [dir="rtl"] .verb-widget .tablet.milo-tooltip.top::before {
    left: 0;
    right: auto;
  }

  [dir="rtl"] .verb-widget .tablet.milo-tooltip.top::after {
    left: 4px;
    right: auto;
  }
}

@media screen and (min-width: 1200px) {
  .verb-widget .milo-tooltip.top::before {
    max-width: 180px;
  }
}

</style><style>#prerender_verb-widget { position: absolute; top: 97px; left: 0; width: 100%; z-index: -1; pointer-events: auto; }</style><meta property="og:locale" content="en-US"><link rel="preload" as="script" crossorigin="anonymous" href="/libs/martech/helpers.js"><link rel="preload" as="script" crossorigin="anonymous" href="/acrobat/blocks/verb-widget/verb-widget.js"><link rel="stylesheet" href="/acrobat/blocks/verb-widget/verb-widget.css"><link rel="preload" as="script" crossorigin="anonymous" href="/acrobat/blocks/unity/unity.js"><link rel="stylesheet" href="/acrobat/blocks/unity/unity.css"><link rel="stylesheet" href="/libs/blocks/global-navigation/global-navigation.css"><link rel="stylesheet" href="https://use.typekit.net/hah7vzn.css"><link rel="stylesheet" href="/libs/blocks/text/text.css"><link rel="stylesheet" href="/libs/blocks/section-metadata/section-metadata.css"><link rel="preload" as="script" href="/marketingtech/d4d114c60e50/a0e989131fd5/launch-5dd5dd2177e6.min.js"><link rel="stylesheet" href="/libs/blocks/global-navigation/base.css"><link rel="preload" as="script" crossorigin="anonymous" href="/libs/blocks/modal/modal.js"><link rel="stylesheet" href="/libs/blocks/modal/modal.css"><link rel="stylesheet" href="/libs/blocks/how-to/how-to.css"><link rel="stylesheet" href="/libs/styles/consonant-play-button.css"><script type="application/ld+json">{"@context":"http://schema.org","@type":"HowTo","name":"How to chat with PDF files","description":"Learn how to use an AI-powered document assistant to chat with your PDFs and other documents. Ask questions and get answers from your files, compare documents, review content, and extract key information and insights.Follow these steps to ask your PDF questions and get instant answers with our PDF chat tool:","publisher":{"@type":"Organization","name":"Adobe","logo":{"@type":"ImageObject","url":"content/dam/cc/icons/Adobe_Corporate_Horizontal_Red_HEX.svg"}},"step":[{"@type":"HowToStep","url":"/acrobat/online/ai-chat-pdf/","name":"Step 1","itemListElement":[{"@type":"HowToDirection","text":"Use the Select files button above, or drag and drop a document into the drop zone."}]},{"@type":"HowToStep","url":"/acrobat/online/ai-chat-pdf/","name":"Step 2","itemListElement":[{"@type":"HowToDirection","text":"Review the suggested questions for fast insights."}]},{"@type":"HowToStep","url":"/acrobat/online/ai-chat-pdf/","name":"Step 3","itemListElement":[{"@type":"HowToDirection","text":"Sign in to ask your PDF questions and get quick AI chat answers."}]},{"@type":"HowToStep","url":"/acrobat/online/ai-chat-pdf/","name":"Step 4","itemListElement":[{"@type":"HowToDirection","text":"Use the PDF AI answers to craft emails, presentations, and more."}]}],"@image":{"@type":"ImageObject","url":"acrobat/online/media_122f85ca7fae25cb9089e09200fa12eeef247556c.png?width=750&format=png&optimize=medium"}}</script><link rel="stylesheet" href="/acrobat/blocks/prompt-card/prompt-card.css"><script type="application/ld+json">{"@context":"https://schema.org","@type":"BreadcrumbList","itemListElement":[{"@type":"ListItem","position":1,"name":"Home","item":"https://www.adobe.com/"},{"@type":"ListItem","position":2,"name":"Acrobat","item":"/acrobat/"},{"@type":"ListItem","position":3,"name":"AI Chat PDF","item":"/acrobat/online/ai-chat-pdf/"}]}</script><link rel="stylesheet" href="https://prod.adobeccstatic.com/unav/1.5/UniversalNav.css"><link rel="stylesheet" type="text/css" href="https://prod.adobeccstatic.com/unav/1.5/layout.bundle.css"><link rel="stylesheet" type="text/css" href="https://prod.adobeccstatic.com/unav/1.5/popover.bundle.css"><link rel="stylesheet" type="text/css" href="https://prod.adobeccstatic.com/unav/1.5/profile.bundle.css"><link rel="stylesheet" href="/libs/blocks/icon-block/icon-block.css"><link rel="stylesheet" href="/libs/blocks/accordion/accordion.css"><script type="application/ld+json">{"@context":"https://schema.org","@type":"FAQPage","mainEntity":[[{"@type":"Question","name":"\n            What kind of questions can I ask my PDF?\n          ","acceptedAnswer":{"text":"You can use the Acrobat AI Assistant tool to ask a PDF all kinds of questions. AI Assistant will then provide a quick answer, using natural language for easier understanding. For example, you can ask AI Assistant to list a document’s five most important points, or you can ask it to draft an email summarizing your document. Don’t know what to ask or what to expect from a PDF AI tool? Simply select one of the common questions suggested by AI Assistant.","@type":"Answer"}},{"@type":"Question","name":"\n            Can I use the tool to chat with other types of documents?\n          ","acceptedAnswer":{"text":"Yes, you can upload a PDF or any other supported document file. If you upload a Microsoft Word document (DOCX), PowerPoint presentation (PPTX), TXT file, or RTF file, the Acrobat online tool will convert the file format to PDF. Then sign in to ask your document questions and get quick answers.","@type":"Answer"}},{"@type":"Question","name":"\n            What languages does the Adobe Acrobat AI chat tool support?\n          ","acceptedAnswer":{"text":"Currently, Adobe Acrobat Al Assistant supports PDFs and documents in English, Japanese, French, German, Italian, Spanish, and Portuguese, with additional languages to be added in future releases. With translation capabilities, you can chat with your documents using original content from or to any of these languages. Al Assistant may inadvertently provide responses in languages other than English, Japanese, French, German, Italian, Spanish, and Portuguese, but these go beyond the intended purpose of the Al Assistant capability and should not be relied upon at this time.","@type":"Answer"}},{"@type":"Question","name":"\n            Can I verify the information in the answers?\n          ","acceptedAnswer":{"text":"You’ll notice that many AI Assistant answers provide attribution by including numbered references as clickable links. When you select one of the numbered links in the AI Assistant chat answer, the AI PDF tool instantly highlights the related source content in your document. This interactive artificial intelligence feature provides a fast, seamless way for users to verify information with a single click. You can copy the chat history and use the answers to craft other content like emails, social posts, or presentations. Learn more about how the chat history is stored.","@type":"Answer"}},{"@type":"Question","name":"\n            What is the best AI assistant for documents?\n          ","acceptedAnswer":{"text":"Adobe Acrobat is one of the best AI assistants for documents. This AI document assistant is designed to help users chat with PDFs and other documents, allowing you to ask questions, compare files, review content, and extract key information.","@type":"Answer"}},{"@type":"Question","name":"\n            How can I ask questions and get answers from my PDF?\n          ","acceptedAnswer":{"text":"With Adobe Acrobat’s PDF chat tool, you can ask questions and get answers directly from your PDF in seconds, without reading the entire document.","@type":"Answer"}},{"@type":"Question","name":"\n            Can I summarize individual sections of a PDF document?\n          ","acceptedAnswer":{"text":"To summarize an individual section of a PDF document, upload a file to the Acrobat AI chat tool and sign in. Then ask your PDF to draft a summary of the specific section you need summarized. You can also ask other research questions, including questions that analyze data across tables shared in the document.","@type":"Answer"}},{"@type":"Question","name":"\n            What is the best AI tool to compare documents?\n          ","acceptedAnswer":{"text":"Adobe Acrobat AI Assistant uses AI to compare documents, helping users identify differences, changes, and important updates across files, making it one of the best tools to quickly compare documents.","@type":"Answer"}},{"@type":"Question","name":"\n            Is AI Assistant a secure tool to use to chat with PDFs?\n          ","acceptedAnswer":{"text":"Security is paramount to Adobe. When you upload documents using this tool, they will be deleted from our servers to respect your privacy if you don’t sign in. Security measures are also built into every PDF created with Acrobat.","@type":"Answer"}},{"@type":"Question","name":"\n            What is the best way to review documents?\n          ","acceptedAnswer":{"text":"One of the best ways to review documents is with our PDF chat tool which functions as an AI document reviewer that helps you analyze documents for accuracy, completeness, and key insights.","@type":"Answer"}},{"@type":"Question","name":"\n            Can I chat with my PDF to analyze documents and extract key information?\n          ","acceptedAnswer":{"text":"Yes. Adobe Acrobat AI Assistant lets you chat with your PDF to analyze PDFs and extract key information such as facts, figures, clauses, and insights.","@type":"Answer"}}]]}</script><link rel="stylesheet" href="/libs/blocks/caas/caas.css"><link rel="stylesheet" href="/libs/blocks/global-navigation/utilities/menu/menu.css"><link rel="stylesheet" href="/libs/blocks/media/media.css"><link rel="stylesheet" href="/acrobat/blocks/rnr/rnr.css"></head>
